**C#:**

C#

Add the MongoDB C# Driver as a dependency in your project:

```sh
dotnet add package MongoDB.Driver
```

Create a file named `IndexService.cs` and copy and paste the
following code into the file.

This index definition indexes the
`plot_embedding_voyage_3_large` field as the `vector` type and
the `genres` and `year` fields as the `filter` type in an
MongoDB Vector Search index. The `plot_embedding_voyage_3_large` field
contains embeddings created using Voyage AI's `voyage-3-large`
embedding model. The index definition specifies `2048` vector
dimensions and measures similarity using `dotProduct` function.

```csharp
namespace query_quick_start;

using MongoDB.Bson;
using MongoDB.Driver;
using System;
using System.Threading;

public class IndexService
{
    // Replace the placeholder with your connection string
    private const string MongoConnectionString = "<connection-string>";
    public void CreateVectorIndex()
    {
        try
        {
            // Connect to your cluster
            var client = new MongoClient(MongoConnectionString);
            var database = client.GetDatabase("sample_mflix");
            var collection = database.GetCollection<BsonDocument>("embedded_movies");

            var searchIndexView = collection.SearchIndexes;
            var name = "vector_index";

            var model = new CreateVectorSearchIndexModel<Movie>(
                m => m.PlotEmbedding,
                name,
                VectorSimilarity.DotProduct,
                2048,
                m => m.Genres,
                m => m.Year)
            {
                Quantization = VectorQuantization.Scalar,
            };

            searchIndexView.CreateOne(model);
            Console.WriteLine($"New search index named {name} is building.");

            // Polling for index status
            Console.WriteLine("Polling to check if the index is ready. This may take up to a minute.");
            bool queryable = false;
            while (!queryable)
            {
                var indexes = searchIndexView.List();
                foreach (var index in indexes.ToEnumerable())
                {
                    if (index["name"] == name)
                    {
                        queryable = index["queryable"].AsBoolean;
                    }
                }
                if (!queryable)
                {
                    Thread.Sleep(5000);
                }
            }
            Console.WriteLine($"{name} is ready for querying.");
        }
        catch (Exception e)
        {
            Console.WriteLine($"Exception: {e.Message}");
        }
    }
}

```

